from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import os
import re

app = Flask(__name__)

w3 = Web3()

ADDRESS_RE = re.compile(r"^0x[a-fA-F0-9]{40}$")


def normalize_address(address: str) -> str:
    if not isinstance(address, str) or not ADDRESS_RE.match(address):
        raise ValueError("Invalid Ethereum address")
    return Web3.to_checksum_address(address)


def recover_address(message: str, signature: str) -> str:
    if not isinstance(message, str) or not isinstance(signature, str):
        raise ValueError("Invalid message or signature")

    if not signature.startswith("0x"):
        signature = "0x" + signature

    encoded_message = encode_defunct(text=message)
    recovered = w3.eth.account.recover_message(encoded_message, signature=signature)
    return Web3.to_checksum_address(recovered)


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200


@app.route("/auth/verify", methods=["POST"])
def auth_verify():
    data = request.get_json(silent=True) or {}

    message = data.get("message")
    signature = data.get("signature")
    address = data.get("address")

    if not message or not signature or not address:
        return jsonify({"error": "message, signature, and address are required"}), 400

    try:
        expected_address = normalize_address(address)
        recovered_address = recover_address(message, signature)
    except Exception as e:
        return jsonify({"error": str(e)}), 400

    authenticated = recovered_address == expected_address

    return jsonify(
        {
            "authenticated": authenticated,
            "expected_address": expected_address,
            "recovered_address": recovered_address,
        }
    ), 200 if authenticated else 401


@app.route("/auth/login", methods=["POST"])
def auth_login():
    data = request.get_json(silent=True) or {}

    message = data.get("message")
    signature = data.get("signature")

    if not message or not signature:
        return jsonify({"error": "message and signature are required"}), 400

    try:
        recovered_address = recover_address(message, signature)
    except Exception as e:
        return jsonify({"error": str(e)}), 400

    token = Web3.keccak(text=f"{recovered_address}:{message}:{signature}").hex()

    return jsonify(
        {
            "authenticated": True,
            "address": recovered_address,
            "token": token,
        }
    ), 200


